// Offline app-shell cache with an OPT-IN update flow. A rebuilt app parks a new
// service worker in `waiting` and the page shows a "new version available"
// prompt; the running session keeps its current (cached) code until the user
// accepts — we never swap code out from under a running game.
//
// `sw-version.js` is generated by `make web` (the wasm content hash). Its
// bytes change on every rebuild, which is how the browser detects a new worker
// and fires the prompt (an `update()` on load forces the re-check). sw.js itself
// is static + committed; the version file is generated + gitignored.
importScripts("./sw-version.js"); // defines self.BUILD_ID
const CACHE = "rustyboi-" + (self.BUILD_ID || "dev");
const SHELL = [
  "./",
  "./index.html",
  "./worker.js",
  "./manifest.webmanifest",
  "./icon-192.png",
  "./icon-512.png",
  "./apple-touch-icon.png",
  "./pkg/rustyboi_web.js",
  "./pkg/rustyboi_web_bg.wasm",
];

self.addEventListener("install", (e) => {
  // Do NOT skipWaiting: park in `waiting` until the page's prompt is accepted, so
  // the running version is never swapped out from under a live session.
  e.waitUntil(caches.open(CACHE).then((c) => c.addAll(SHELL)));
});

self.addEventListener("activate", (e) => {
  e.waitUntil(
    caches.keys()
      .then((keys) => Promise.all(keys.filter((k) => k !== CACHE).map((k) => caches.delete(k))))
      .then(() => self.clients.claim())
  );
});

// The page posts this when the user accepts the update; take over immediately.
self.addEventListener("message", (e) => {
  if (e.data === "SKIP_WAITING") self.skipWaiting();
});

// Cache-first: serve THIS worker's cached shell, so the running version is stable
// + offline-capable and only changes after the user opts into a new worker (which
// has its own CACHE). Uncached same-origin GETs fall through to the network.
self.addEventListener("fetch", (e) => {
  const req = e.request;
  if (req.method !== "GET" || new URL(req.url).origin !== self.location.origin) return;
  e.respondWith(
    caches.open(CACHE).then((c) => c.match(req).then((hit) => hit || fetch(req)))
  );
});
